  'Reframing an objection means turning a concern into a ___.': { prompt: 'Reformular una objeción significa convertir una preocupación en una ___.', options: ['Razón para comprar', 'Broma', 'Queja', 'Descuento'], correctAnswer: 'Razón para comprar' },
